#!/usr/bin/env bash
set -Eeuo pipefail
RED="\033[0;31m"; GRN="\033[0;32m"; CYN="\033[0;36m"; RST="\033[0m"
info(){ echo -e "  ${CYN}i${RST}  $*"; }
ok(){ echo -e "  ${GRN}+${RST}  $*"; }
err(){ echo -e "  ${RED}x${RST}  $*"; exit 1; }
trap 'echo -e "
${RED}Install failed near line $LINENO.${RST}"' ERR
[[ $EUID -ne 0 ]] && err "Run as root on the Proxmox host"
for cmd in pct pvesh pveam pvesm; do command -v "$cmd" >/dev/null 2>&1 || err "$cmd not found"; done
CTID=$(pvesh get /cluster/nextid)
STORAGE=$(pvesm status | awk 'NR>1 && $1=="local-lvm"{print $1; exit}')
[[ -z "$STORAGE" ]] && STORAGE=$(pvesm status | awk 'NR>1 && $1=="local"{print $1; exit}')
[[ -z "$STORAGE" ]] && STORAGE=$(pvesm status | awk 'NR>1 {print $1; exit}')
[[ -z "$STORAGE" ]] && err "No storage found"
ok "CTID: $CTID"
ok "Storage: $STORAGE"
info "Updating template catalog..."
pveam update >/dev/null 2>&1 || true
TEMPLATE=$(pveam available 2>/dev/null | awk '/^system[[:space:]]+alpine-[0-9.]+-default/ && /amd64/ {print $2}' | sort -V | tail -n1)
[[ -z "$TEMPLATE" ]] && err "No Alpine template found in pveam available"
ok "Template: $TEMPLATE"
info "Downloading template if needed..."
pveam download local "$TEMPLATE" >/dev/null 2>&1 || true
TEMPLATE_VOL=$(pveam list local 2>/dev/null | awk -v t="$TEMPLATE" '$1 ~ t {print $1; exit}')
[[ -z "$TEMPLATE_VOL" ]] && err "Template was not found on local storage after download: $TEMPLATE"
ok "Template volume: $TEMPLATE_VOL"
info "Creating LXC..."
pct create "$CTID" "$TEMPLATE_VOL" --hostname homelab-dashboard --unprivileged 1 --cores 1 --memory 256 --rootfs "$STORAGE:2" --net0 name=eth0,bridge=vmbr0,ip=dhcp,ip6=auto --onboot 1 >/dev/null
pct start "$CTID" >/dev/null
sleep 6
pct exec "$CTID" -- sh -lc 'apk update >/dev/null && apk add --no-cache nginx >/dev/null'
cat <<'EOFHTML' | base64 -d | pct exec "$CTID" -- sh -lc 'mkdir -p /usr/share/nginx/html && cat > /usr/share/nginx/html/index.html'

EOFHTML
pct exec "$CTID" -- sh -lc 'cat > /etc/nginx/http.d/default.conf <<"EOF"
server {
  listen 80;
  server_name _;
  root /usr/share/nginx/html;
  index index.html;
  location / {
    try_files \$uri \$uri/ /index.html;
  }
}
EOF'
pct exec "$CTID" -- sh -lc 'rc-update add nginx default >/dev/null && rc-service nginx restart >/dev/null'
IP=$(pct exec "$CTID" -- sh -lc "ip -4 addr show eth0 | awk '/inet /{print \\$2}' | cut -d/ -f1 | head -n1" 2>/dev/null || true)
echo
echo "Homelab Dashboard ready"
echo "CTID: $CTID"
echo "URL: http://$IP"
echo "Shell: pct exec $CTID -- ash"
